// Domain checkout pricing (USD → ZAR with markup).

const DOMAIN_USD_ZAR = Number(Deno.env.get('DOMAIN_USD_ZAR_RATE') ?? '18.5');
const DOMAIN_MARKUP_PERCENT = Number(Deno.env.get('DOMAIN_MARKUP_PERCENT') ?? '15');

export function domainCheckoutZar(usdPrice: number): number {
  return Math.ceil(usdPrice * DOMAIN_USD_ZAR * (1 + DOMAIN_MARKUP_PERCENT / 100));
}

/** Default platform email addresses (override via NOTIFY_FROM / NOTIFY_TO secrets). */

export const PLATFORM_INFO_EMAIL = 'info@redfacepay.co.za';

/** Personal boss inbox — set BOSS_EMAIL secret (e.g. redfacesa@gmail.com). */
export const DEFAULT_BOSS_EMAIL = 'redfacesa@gmail.com';

export const DEFAULT_NOTIFY_FROM = `RedFace Pay <${PLATFORM_INFO_EMAIL}>`;

export const DEFAULT_NOTIFY_TO = PLATFORM_INFO_EMAIL;

/** Developer API tier billing — amounts aligned with src/lib/pluginEcosystem.ts */

export const DEVELOPER_API_TIER_AMOUNTS_ZAR = {
  developer: 199,
  growth: 999,
} as const;

export type PaidDeveloperTier = keyof typeof DEVELOPER_API_TIER_AMOUNTS_ZAR;

export function developerTierAmountZar(tier: PaidDeveloperTier): number {
  return DEVELOPER_API_TIER_AMOUNTS_ZAR[tier];
}

export function isPaidDeveloperTier(tier: string): tier is PaidDeveloperTier {
  return tier === 'developer' || tier === 'growth';
}

import type { VerifyTransactionResult } from './types.ts';

/**
 * Legacy Paystack verify envelope still expected by redface-pay confirm paths.
 * Maps PaymentProvider.verifyTransaction → { status, data, message }.
 */
export function verifyResultToLegacyEnvelope(result: VerifyTransactionResult): Record<string, unknown> {
  return {
    status: result.ok,
    message: result.message,
    data: {
      status: result.status,
      amount: result.amountSubunits,
      currency: result.currency,
      metadata: result.metadata ?? {},
    },
  };
}

/** Platform fee plan resolution — premium subscribers pay 0% while active. */

export type MerchantPlan = 'small' | 'marketplace' | 'premium' | 'founding';

export function defaultPlanPercent(plan: MerchantPlan): number {
  switch (plan) {
    case 'founding':
      return 1.5;
    case 'marketplace':
      return 5;
    case 'premium':
      return 0;
    default:
      return 2;
  }
}

export function feePlanFromMerchant(merchant: {
  merchant_plan?: string | null;
  subscription_status?: string | null;
}): MerchantPlan {
  const raw = String(merchant.merchant_plan ?? 'small');
  if (raw === 'founding') return 'founding';
  if (raw === 'marketplace') return 'marketplace';
  if (raw === 'premium' && merchant.subscription_status === 'active') return 'premium';
  return 'small';
}

// Minimal name.com API client (DNS + domain ops).

const NAMECOM_USER = Deno.env.get('NAMECOM_USERNAME') ?? '';
const NAMECOM_TOKEN = Deno.env.get('NAMECOM_API_TOKEN') ?? '';
const NAMECOM_BASE = (Deno.env.get('NAMECOM_API_BASE') ?? 'https://api.name.com').replace(/\/$/, '');

function namecomAuthHeader() {
  return `Basic ${btoa(`${NAMECOM_USER}:${NAMECOM_TOKEN}`)}`;
}

export async function namecomFetch(path: string, init: RequestInit = {}) {
  if (!NAMECOM_USER || !NAMECOM_TOKEN) {
    return { ok: false, status: 503, data: { error: 'Domain API not configured' } };
  }
  const res = await fetch(`${NAMECOM_BASE}/core/v1${path}`, {
    ...init,
    headers: {
      Authorization: namecomAuthHeader(),
      'Content-Type': 'application/json',
      Accept: 'application/json',
      ...(init.headers || {}),
    },
  });
  let data: unknown;
  try {
    data = await res.json();
  } catch {
    data = { error: await res.text() };
  }
  return { ok: res.ok, status: res.status, data };
}

import type { SupabaseClient } from 'https://esm.sh/@supabase/supabase-js@2.49.1';

/** Mark pending buyer checkout intents completed after a verified payment. */
export async function completeBuyerPaymentIntents(
  admin: SupabaseClient,
  opts: {
    buyerEmail?: string | null;
    merchantId?: string | null;
    sessionToken?: string | null;
    clientIntentId?: string | null;
    reference?: string | null;
  },
): Promise<void> {
  const hasRef = !!opts.reference?.trim();
  const email = opts.buyerEmail?.trim().toLowerCase();
  if (!hasRef && (!email || !email.includes('@'))) return;

  const { error } = await admin.rpc('buyer_payment_intent_complete', {
    p_buyer_email: email || null,
    p_merchant_id: opts.merchantId ?? null,
    p_intent_id: null,
    p_payment_session_token: opts.sessionToken ?? null,
    p_client_intent_id: opts.clientIntentId ?? null,
    p_reference: opts.reference ?? null,
  });
  if (error) {
    console.warn('[buyerPaymentIntents] complete failed', error.message);
  }
}

/** Reconcile POS split sales when the card portion clears via Paystack. */

import type { SupabaseClient } from 'https://esm.sh/@supabase/supabase-js@2';

export async function completePosSplitCardTender(
  admin: SupabaseClient,
  saleId: string,
  reference: string,
  transactionId?: string | null,
): Promise<{ ok: boolean; error?: string }> {
  const id = String(saleId ?? '').trim();
  if (!id) return { ok: false, error: 'sale_id_required' };

  const { data, error } = await admin.rpc('complete_pos_split_card_tender', {
    p_sale_id: id,
    p_reference: reference,
    p_transaction_id: transactionId ?? null,
  });

  if (error) return { ok: false, error: error.message };
  const row = (data ?? {}) as { ok?: boolean; error?: string };
  if (!row.ok) return { ok: false, error: row.error ?? 'complete_failed' };
  return { ok: true };
}

export function posSaleIdFromMetadata(metadata: Record<string, unknown>): string | null {
  const id = String(metadata.pos_sale_id ?? '').trim();
  return id.length >= 32 ? id : null;
}

/** Paystack plan codes & pricing for marketplace boosts (server-side). */

export const SPONSORED_7D_ZAR = Number(Deno.env.get('SPONSORED_LISTING_7D_ZAR') ?? '99');
export const SPONSORED_14D_ZAR = Number(Deno.env.get('SPONSORED_LISTING_14D_ZAR') ?? '179');
export const SPONSORED_30D_ZAR = Number(Deno.env.get('SPONSORED_LISTING_30D_ZAR') ?? '299');

export function normalizeSponsoredDays(raw: number): 7 | 14 | 30 {
  if (raw <= 7) return 7;
  if (raw <= 14) return 14;
  return 30;
}

export function sponsoredListingPrice(days: number): number {
  const d = normalizeSponsoredDays(days);
  if (d === 7) return SPONSORED_7D_ZAR;
  if (d === 14) return SPONSORED_14D_ZAR;
  return SPONSORED_30D_ZAR;
}

export function sponsoredPlanCode(days: number): string {
  const d = normalizeSponsoredDays(days);
  if (d === 7) return Deno.env.get('SPONSORED_PLAN_7D') ?? 'PLN_ggm8dwotpsdncfb';
  if (d === 14) return Deno.env.get('SPONSORED_PLAN_14D') ?? 'PLN_qn4oukab6jodg1x';
  return Deno.env.get('SPONSORED_PLAN_30D') ?? 'PLN_wsyk1xw3iyx60vb';
}

/** RedFace Studio subscription checkout — keep in sync with redface_studio/server/plan-limits.mjs */

export type StudioPlanId = 'starter' | 'pro';
export type StudioInterval = 'monthly' | 'yearly';

const PLAN_PRICES_ZAR: Record<StudioPlanId, { monthly: number; yearly: number }> = {
  starter: { monthly: 699, yearly: 579 * 12 },
  pro: { monthly: 1099, yearly: 919 * 12 },
};

export function studioAmountMajor(planId: string, interval: string): number | null {
  const id = planId as StudioPlanId;
  const row = PLAN_PRICES_ZAR[id];
  if (!row) return null;
  return interval === 'yearly' ? row.yearly : row.monthly;
}

export function studioPaystackPlanCode(planId: string, interval: string): string | null {
  const key = `PAYSTACK_PLAN_${planId.toUpperCase()}_${interval === 'yearly' ? 'YEARLY' : 'MONTHLY'}`;
  const code = Deno.env.get(key)?.trim();
  return code || null;
}

export function normalizeStudioPlanId(raw: string): StudioPlanId | null {
  const id = String(raw || '').toLowerCase();
  if (id === 'starter' || id === 'pro') return id;
  return null;
}

import { activeProviderName } from './types.ts';
import type { PaymentProvider, PaymentRail } from './types.ts';
import { createPaystackProvider, initializePaystackCheckoutFull } from './paystack.ts';
import { createStripeProvider } from './stripe.ts';

export * from './types.ts';
export { verifyResultToLegacyEnvelope } from './verifyEnvelope.ts';
export { initializePaystackCheckoutFull };

let cached: PaymentRail | null = null;

/** Singleton rail for edge functions. Set PAYMENT_PROVIDER=paystack|stripe. */
export function getPaymentProvider(): PaymentRail {
  if (cached) return cached;
  const name = activeProviderName();
  const paystackSecret = Deno.env.get('PAYSTACK_SECRET_KEY') ?? '';
  const stripeSecret = Deno.env.get('STRIPE_SECRET_KEY') ?? '';

  if (name === 'stripe') {
    cached = createStripeProvider(stripeSecret);
  } else {
    cached = createPaystackProvider(paystackSecret);
  }
  return cached;
}

/** FAL alias — same singleton. */
export const getPaymentRail = getPaymentProvider;

/** Reset cached provider (tests). */
export function resetPaymentProviderCache(): void {
  cached = null;
}

import type { SupabaseClient } from 'https://esm.sh/@supabase/supabase-js@2';

export type EmitBusinessEventOpts = {
  merchantId: string;
  eventType: string;
  actorType?: 'buyer' | 'merchant' | 'system';
  actorUserId?: string | null;
  customerEmail?: string | null;
  productId?: string | null;
  reference?: string | null;
  amount?: number | null;
  currency?: string | null;
  source?: string | null;
  idempotencyKey?: string | null;
  payload?: Record<string, unknown>;
};

export async function emitMerchantBusinessEvent(
  admin: SupabaseClient,
  opts: EmitBusinessEventOpts,
): Promise<void> {
  const { error } = await admin.rpc('append_merchant_business_event', {
    p_merchant_id: opts.merchantId,
    p_event_type: opts.eventType,
    p_actor_type: opts.actorType ?? 'system',
    p_actor_user_id: opts.actorUserId ?? null,
    p_customer_email: opts.customerEmail ?? null,
    p_product_id: opts.productId ?? null,
    p_reference: opts.reference ?? null,
    p_amount: opts.amount ?? null,
    p_currency: opts.currency ?? null,
    p_source: opts.source ?? 'edge',
    p_idempotency_key: opts.idempotencyKey ?? null,
    p_payload: opts.payload ?? {},
  });
  if (error) console.error('append_merchant_business_event', opts.eventType, error.message);
}

import type { SupabaseClient } from 'https://esm.sh/@supabase/supabase-js@2';

/** Env fallback when admins table is empty (comma-separated). */
export function adminEmailAllowList(): string[] {
  return (Deno.env.get('ADMIN_EMAILS') ?? 'info@redfacepay.co.za')
    .split(',')
    .map((s) => s.trim().toLowerCase())
    .filter(Boolean);
}

/** True if email is in public.admins or ADMIN_EMAILS env fallback. */
export async function isAdminEmail(
  admin: SupabaseClient,
  email: string | null | undefined,
): Promise<boolean> {
  const normalized = String(email ?? '').trim().toLowerCase();
  if (!normalized) return false;

  const { data, error } = await admin
    .from('admins')
    .select('email')
    .ilike('email', normalized)
    .maybeSingle();

  if (!error && data?.email) return true;
  return adminEmailAllowList().includes(normalized);
}

export async function requireAdminFromRequest(
  admin: SupabaseClient,
  req: Request,
): Promise<string | null> {
  const token = (req.headers.get('Authorization') ?? '').replace(/^Bearer\s+/i, '').trim();
  if (!token) return null;
  const { data, error } = await admin.auth.getUser(token);
  const email = data?.user?.email?.toLowerCase();
  if (error || !email) return null;
  return (await isAdminEmail(admin, email)) ? email : null;
}

export function authorizeCron(req: Request): boolean {
  const secret = Deno.env.get('CRON_SECRET') ?? '';
  if (!secret) return false;
  const h = req.headers.get('x-cron-secret')
    ?? (req.headers.get('authorization') ?? '').replace(/^Bearer\s+/i, '').trim();
  return h === secret;
}

/** Minimum card checkout amounts — keep in sync with src/lib/paymentLimits.ts */

export const MIN_CARD_PAYMENT_ZAR_MAJOR = 5;
export const MIN_CARD_PAYMENT_ZAR_SUBUNITS = MIN_CARD_PAYMENT_ZAR_MAJOR * 100;

export function minCardAmountMessage(currency: string): string {
  if (currency.toUpperCase() === 'ZAR') {
    return `Minimum card payment is R${MIN_CARD_PAYMENT_ZAR_MAJOR}. Amounts under R${MIN_CARD_PAYMENT_ZAR_MAJOR} often fail after payment partner fees. Try R${MIN_CARD_PAYMENT_ZAR_MAJOR} or more.`;
  }
  return 'This amount is too small for card checkout after processing fees. Try a higher amount.';
}

export function minCardAmountSubunits(currency: string): number {
  return currency.toUpperCase() === 'ZAR' ? MIN_CARD_PAYMENT_ZAR_SUBUNITS : 100;
}

export function assertCardAmountViable(amountSub: number, currency: string): string | null {
  const cur = currency.toUpperCase();
  const minSub = minCardAmountSubunits(cur);
  if (amountSub < minSub) return minCardAmountMessage(currency);
  const estProcessorFee =
    cur === 'ZAR' ? Math.ceil(amountSub * 0.029) + 100 : Math.ceil(amountSub * 0.039);
  if (amountSub - estProcessorFee <= 0) return minCardAmountMessage(currency);
  return null;
}

export function minChargeSubunits(currency?: string): number {
  return minCardAmountSubunits(String(currency ?? 'ZAR'));
}

export function minChargeMessage(currency?: string): string {
  const cur = String(currency ?? 'ZAR').toUpperCase();
  if (cur === 'ZAR') {
    return `Minimum charge amount is R${MIN_CARD_PAYMENT_ZAR_MAJOR}.00`;
  }
  return 'Minimum charge amount is too low for card checkout';
}

/** Activate a marketplace sponsorship row (shared by redface-pay + paystack-webhook). */

import type { SupabaseClient } from 'https://esm.sh/@supabase/supabase-js@2';
import { normalizeSponsoredDays } from './sponsoredListings.ts';

export async function activateSponsoredListingRow(
  admin: SupabaseClient,
  sponsoredId: string,
  reference: string,
  amountPaid: number,
  currency: string | null,
  durationDays: number,
  subscriptionCode?: string | null,
  extraMeta?: Record<string, unknown>,
) {
  if (!sponsoredId) return;
  await admin.rpc('expire_sponsored_listings').then(() => {}, () => {});
  const { data: sponsoredRow } = await admin
    .from('merchant_sponsored_listings')
    .select('product_id, status, ends_at, meta')
    .eq('id', sponsoredId)
    .maybeSingle();
  if (sponsoredRow?.product_id) {
    await admin.from('merchant_sponsored_listings')
      .update({ status: 'expired' })
      .eq('product_id', sponsoredRow.product_id)
      .eq('status', 'active')
      .neq('id', sponsoredId);
  }
  const days = normalizeSponsoredDays(durationDays);
  const now = new Date();
  const base = sponsoredRow?.status === 'active' && sponsoredRow.ends_at
    && new Date(sponsoredRow.ends_at).getTime() > now.getTime()
    ? new Date(sponsoredRow.ends_at)
    : now;
  const ends = new Date(base.getTime() + days * 86400000);
  const meta = {
    ...((sponsoredRow?.meta as Record<string, unknown>) || {}),
    ...(extraMeta || {}),
  };
  const patch: Record<string, unknown> = {
    status: 'active',
    paystack_reference: reference,
    ends_at: ends.toISOString(),
    amount_paid: amountPaid,
    currency: currency ?? 'ZAR',
    priority: 100 + days,
    duration_days: days,
    meta,
  };
  if (sponsoredRow?.status !== 'active') patch.starts_at = now.toISOString();
  if (subscriptionCode) patch.paystack_subscription_code = subscriptionCode;
  await admin.from('merchant_sponsored_listings').update(patch)
    .eq('id', sponsoredId)
    .in('status', ['pending_payment', 'active']);
}

/** Invoice deposit / balance checkout amounts. */

import type { SupabaseClient } from 'https://esm.sh/@supabase/supabase-js@2';

export type InvoicePaymentKind = 'deposit' | 'balance' | 'full';

export type ResolvedInvoiceCheckout = {
  ok: boolean;
  error?: string;
  invoice_id?: string;
  merchant_id?: string;
  payment_kind?: InvoicePaymentKind;
  amount?: number;
  currency?: string;
  total?: number;
  amount_paid?: number;
  balance_due?: number;
  deposit_percent?: number | null;
  deposit_amount?: number | null;
  invoice_number?: string;
  label?: string;
};

export async function resolveInvoiceCheckout(
  admin: SupabaseClient,
  invoiceId: string,
  paymentKind: InvoicePaymentKind = 'full',
): Promise<ResolvedInvoiceCheckout> {
  const { data, error } = await admin.rpc('resolve_invoice_checkout', {
    p_invoice_id: invoiceId,
    p_payment_kind: paymentKind,
  });
  if (error) return { ok: false, error: error.message };
  return (data ?? { ok: false, error: 'unknown' }) as ResolvedInvoiceCheckout;
}

export async function applyInvoicePayment(
  admin: SupabaseClient,
  invoiceId: string,
  paidAmount: number,
  reference: string,
  paymentKind: InvoicePaymentKind,
): Promise<void> {
  const { data: inv } = await admin
    .from('merchant_invoices')
    .select('id, total, amount_paid, deposit_percent, status')
    .eq('id', invoiceId)
    .maybeSingle();
  if (!inv) return;

  const newPaid = Number(inv.amount_paid ?? 0) + paidAmount;
  const total = Number(inv.total ?? 0);
  const fullyPaid = newPaid >= total - 0.009;

  const patch: Record<string, unknown> = {
    amount_paid: newPaid,
    paystack_reference: reference,
    updated_at: new Date().toISOString(),
  };

  if (paymentKind === 'deposit' && !inv.deposit_paid_at) {
    patch.deposit_paid_at = new Date().toISOString();
  }

  if (fullyPaid) {
    patch.status = 'paid';
    patch.paid_at = new Date().toISOString();
  } else if (newPaid > 0) {
    patch.status = 'partial';
  }

  await admin.from('merchant_invoices').update(patch).eq('id', invoiceId);
}

/** Payment Rail abstraction — Paystack today, SoftPOS / Stripe when live. */

/**
 * FAL name: PaymentRail. PaymentProvider is the legacy alias kept for
 * existing imports until call sites migrate.
 */
export type PaymentRailName = 'paystack' | 'stripe' | 'manual';

/** @deprecated Prefer PaymentRailName */
export type PaymentProviderName = PaymentRailName;

export type InitializeCheckoutInput = {
  email: string;
  amountSubunits: number;
  currency: string;
  reference: string;
  callbackUrl: string;
  metadata?: Record<string, unknown>;
  subaccount?: string | null;
  channels?: string[];
};

export type InitializeCheckoutResult = {
  ok: boolean;
  provider: PaymentRailName;
  /** FAL alias — same as provider. */
  rail?: PaymentRailName;
  reference?: string;
  access_code?: string;
  authorization_url?: string;
  message?: string;
};

export type VerifyTransactionResult = {
  ok: boolean;
  provider: PaymentRailName;
  rail?: PaymentRailName;
  /** Provider payment status string (e.g. success, failed, pending). */
  status?: string;
  amountSubunits?: number;
  currency?: string;
  metadata?: Record<string, unknown>;
  message?: string;
};

/**
 * Payment Rail connector. SoftPOS partners implement the same contract
 * (initialize / verify / optional refund) without business modules knowing.
 */
export interface PaymentRail {
  readonly name: PaymentRailName;
  readonly id?: PaymentRailName;
  initializeCheckout(input: InitializeCheckoutInput): Promise<InitializeCheckoutResult>;
  verifyTransaction(reference: string): Promise<VerifyTransactionResult>;
}

/** @deprecated Prefer PaymentRail */
export type PaymentProvider = PaymentRail;

/** Read active rail from env. Defaults to paystack. */
export function activeProviderName(): PaymentRailName {
  const raw = (Deno.env.get('PAYMENT_PROVIDER') ?? 'paystack').toLowerCase();
  if (raw === 'stripe') return 'stripe';
  if (raw === 'manual') return 'manual';
  return 'paystack';
}

export const activeRailName = activeProviderName;

export function isTestMode(secretKey: string): boolean {
  return secretKey.startsWith('sk_test_');
}

// RedFace Pay — Paystack Apple Pay domain registration (server-side only).
//
// Apple Pay domain registration is an account-level operation that requires the
// Paystack SECRET key, so it must run inside the Edge Function. Reads the key
// from the PAYSTACK_SECRET_KEY secret — never the browser.
//
// Merge these into your existing `redface-pay` action switch (see snippet below).

const PAYSTACK_BASE = 'https://api.paystack.co';

function secret(): string {
  const key = Deno.env.get('PAYSTACK_SECRET_KEY');
  if (!key) throw new Error('PAYSTACK_SECRET_KEY is not configured');
  return key;
}

// POST /apple-pay/domain — register one top-level domain or subdomain.
export async function registerApplePayDomain(payload: { domainName?: string }) {
  const res = await fetch(`${PAYSTACK_BASE}/apple-pay/domain`, {
    method: 'POST',
    headers: { Authorization: `Bearer ${secret()}`, 'Content-Type': 'application/json' },
    body: JSON.stringify({ domainName: payload.domainName }),
  });
  return await res.json();
}

// GET /apple-pay/domain — list registered domains.
export async function listApplePayDomains() {
  const res = await fetch(`${PAYSTACK_BASE}/apple-pay/domain`, {
    headers: { Authorization: `Bearer ${secret()}` },
  });
  return await res.json();
}

// DELETE /apple-pay/domain — unregister a domain.
export async function unregisterApplePayDomain(payload: { domainName?: string }) {
  const res = await fetch(`${PAYSTACK_BASE}/apple-pay/domain`, {
    method: 'DELETE',
    headers: { Authorization: `Bearer ${secret()}`, 'Content-Type': 'application/json' },
    body: JSON.stringify({ domainName: payload.domainName }),
  });
  return await res.json();
}

/*
WIRING — add to your existing `redface-pay` switch on `action`:

  import { registerApplePayDomain, listApplePayDomains, unregisterApplePayDomain } from './apple-pay.ts';

  switch (action) {
