const PAYSTACK_BASE = 'https://api.paystack.co';

export function friendlyRefundError(message: string): string {
  const m = message.trim();
  if (/insufficient balance/i.test(m)) {
    return 'Paystack balance is too low to process this refund. Top up your Paystack account and try again.';
  }
  if (/fully reversed/i.test(m)) {
    return 'This payment has already been fully refunded.';
  }
  return m || 'Paystack refund failed';
}

export type PaystackRefundInput = {
  transactionReference: string;
  amountMajor: number;
  currency?: string;
  customerNote?: string;
  merchantNote?: string;
  secret: string;
};

export type PaystackRefundResult =
  | { ok: true; paystackId: string; paystackStatus: string; raw: Record<string, unknown> }
  | { ok: false; message: string; raw: Record<string, unknown> };

export async function createPaystackRefund(input: PaystackRefundInput): Promise<PaystackRefundResult> {
  const amountSubunits = Math.round(Number(input.amountMajor) * 100);
  if (!input.transactionReference) {
    return { ok: false, message: 'Transaction reference is required', raw: {} };
  }
  if (!amountSubunits || amountSubunits <= 0) {
    return { ok: false, message: 'Refund amount must be positive', raw: {} };
  }

  const body: Record<string, unknown> = {
    transaction: input.transactionReference,
    amount: amountSubunits,
  };
  if (input.currency) body.currency = input.currency;
  if (input.customerNote) body.customer_note = input.customerNote;
  if (input.merchantNote) body.merchant_note = input.merchantNote;

  const res = await fetch(`${PAYSTACK_BASE}/refund`, {
    method: 'POST',
    headers: {
      Authorization: `Bearer ${input.secret}`,
      'Content-Type': 'application/json',
    },
    body: JSON.stringify(body),
  });

  const raw = (await res.json()) as Record<string, unknown>;
  if (!raw.status) {
    return {
      ok: false,
      message: friendlyRefundError(String(raw.message ?? 'Paystack refund failed')),
      raw,
    };
  }

  const data = (raw.data ?? {}) as Record<string, unknown>;
  return {
    ok: true,
    paystackId: String(data.id ?? ''),
    paystackStatus: String(data.status ?? 'pending'),
    raw,
  };
}

/**
 * Business Fact Envelope — shared shape for every kernel-emitted fact.
 *
 * correlation_id ties together one business operation (e.g. a checkout).
 * causation_id names the immediate parent fact that caused this one.
 *
 * @see docs/codex/platform/commerce-language-specification.md
 */

export type BusinessFactEnvelope = {
  id: string;
  type: string;
  version: number;
  occurred_at: string;
  producer: string;
  correlation_id: string;
  causation_id: string | null;
  merchant_id: string | null;
  reference: string | null;
  payload: Record<string, unknown>;
};

export type CreateEnvelopeOpts = {
  type: string;
  producer?: string;
  merchantId?: string | null;
  reference?: string | null;
  correlationId?: string | null;
  causationId?: string | null;
  version?: number;
  payload?: Record<string, unknown>;
  /** Stable id for idempotent emission; defaults to a new UUID. */
  id?: string | null;
};

export function correlationIdForPayment(reference: string): string {
  return `corr_pay_${String(reference).replace(/[^a-zA-Z0-9_-]/g, '').slice(0, 80)}`;
}

export function createBusinessFactEnvelope(opts: CreateEnvelopeOpts): BusinessFactEnvelope {
  const reference = opts.reference ? String(opts.reference) : null;
  const correlation =
    String(opts.correlationId ?? '').trim()
    || (reference ? correlationIdForPayment(reference) : `corr_${crypto.randomUUID().replace(/-/g, '')}`);

  return {
    id: String(opts.id ?? '').trim() || crypto.randomUUID(),
    type: opts.type,
    version: opts.version ?? 1,
    occurred_at: new Date().toISOString(),
    producer: opts.producer ?? 'commerce-kernel',
    correlation_id: correlation,
    causation_id: opts.causationId ? String(opts.causationId) : null,
    merchant_id: opts.merchantId ?? null,
    reference,
    payload: opts.payload ?? {},
  };
}

/** Flatten envelope metadata into a payload object for legacy RPC callers. */
export function envelopeIntoPayload(envelope: BusinessFactEnvelope): Record<string, unknown> {
  return {
    ...envelope.payload,
    _envelope: {
      id: envelope.id,
      type: envelope.type,
      version: envelope.version,
      occurred_at: envelope.occurred_at,
      producer: envelope.producer,
      correlation_id: envelope.correlation_id,
      causation_id: envelope.causation_id,
    },
  };
}

/** Boss / platform alert emails — best-effort, never throws. */

import { DEFAULT_NOTIFY_FROM, DEFAULT_NOTIFY_TO, DEFAULT_BOSS_EMAIL } from './platformEmail.ts';

export type BossEvent =
  | 'user_signup'
  | 'merchant_application'
  | 'payment_failed'
  | 'transfer_failed'
  | 'webhook_error'
  | 'client_error';

/** Distinct inbox addresses (BOSS_EMAIL + NOTIFY_TO). */
export function bossRecipients(): string[] {
  const out = new Set<string>();
  const boss = Deno.env.get('BOSS_EMAIL')?.trim().toLowerCase() ?? DEFAULT_BOSS_EMAIL.toLowerCase();
  const notify = (Deno.env.get('NOTIFY_TO') ?? DEFAULT_NOTIFY_TO).trim().toLowerCase();
  if (boss) out.add(boss);
  if (notify) out.add(notify);
  return [...out];
}

async function sendOne(
  resendKey: string,
  from: string,
  to: string,
  subject: string,
  html: string,
): Promise<boolean> {
  try {
    const res = await fetch('https://api.resend.com/emails', {
      method: 'POST',
      headers: {
        Authorization: `Bearer ${resendKey}`,
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({ from, to: [to], subject, html }),
    });
    if (!res.ok) {
      console.error('[bossNotify] resend failed', to, res.status, await res.text());
      return false;
    }
    return true;
  } catch (err) {
    console.error('[bossNotify] send error', to, err);
    return false;
  }
}

export async function notifyBoss(opts: {
  subject: string;
  html: string;
  from?: string;
}): Promise<boolean> {
  const resendKey = Deno.env.get('RESEND_API_KEY') ?? '';
  const from = opts.from ?? Deno.env.get('NOTIFY_FROM') ?? DEFAULT_NOTIFY_FROM;
  const recipients = bossRecipients();
  if (!resendKey || recipients.length === 0) return false;

  let any = false;
  for (const to of recipients) {
    if (await sendOne(resendKey, from, to, opts.subject, opts.html)) any = true;
  }
  return any;
}

export function bossAlertHtml(event: BossEvent, lines: Record<string, string>): string {
  const rows = Object.entries(lines)
    .map(([k, v]) => `<tr><td style="padding:4px 12px 4px 0;color:#666;">${k}</td><td><strong>${v}</strong></td></tr>`)
    .join('');
  return `
    <div style="font-family:sans-serif;max-width:560px;margin:0 auto;color:#1a1a1a;">
      <p style="color:#FF4B4B;font-weight:bold;margin:0 0 8px;">RedFace Pay alert · ${event}</p>
      <table style="font-size:14px;border-collapse:collapse;">${rows}</table>
      <p style="font-size:12px;color:#888;margin-top:16px;">${new Date().toISOString()}</p>
    </div>
  `.trim();
}

/**
 * Loyalty consumer — awards points from payment.recorded (idempotent).
 */

import type { SupabaseClient } from 'https://esm.sh/@supabase/supabase-js@2';
import { emitMerchantBusinessEvent } from './businessEvents.ts';
import { resolveCheckoutMetadata } from './transactionLineItems.ts';

const NON_LOYALTY_PURCHASE_TYPES = new Set([
  'domain',
  'domain_renewal',
  'plan_subscription',
  'product_subscription',
  'developer_api_subscription',
  'sponsored_listing',
  'agency',
  'studio_subscription',
]);

export async function consumeLoyaltyFromPaymentRecorded(
  admin: SupabaseClient,
  input: {
    reference: string;
    merchantId: string;
    buyerEmail?: string | null;
    amount?: number | null;
    currency?: string | null;
    paymentSessionId?: string | null;
  },
): Promise<{ ok: boolean; skipped?: boolean; reason?: string; points?: number }> {
  const reference = String(input.reference ?? '').trim();
  const buyerEmail = String(input.buyerEmail ?? '').trim().toLowerCase();
  const amount = Number(input.amount ?? 0);
  if (!reference || !buyerEmail || !(amount > 0)) {
    return { ok: true, skipped: true, reason: 'missing_buyer_or_amount' };
  }

  const meta = await resolveCheckoutMetadata(admin, {
    reference,
    paymentSessionId: input.paymentSessionId ?? null,
  });
  const purchaseType = String(meta.purchase_type ?? meta.object_type ?? '').toLowerCase();
  if (NON_LOYALTY_PURCHASE_TYPES.has(purchaseType)) {
    return { ok: true, skipped: true, reason: 'non_loyalty_purchase' };
  }

  const { data, error } = await admin.rpc('award_loyalty_points', {
    p_merchant_id: input.merchantId,
    p_buyer_email: buyerEmail,
    p_amount: amount,
    p_reference: reference,
  });
  if (error) {
    console.error('award_loyalty_points', reference, error.message);
    return { ok: false, reason: error.message };
  }

  const row = (data ?? {}) as { ok?: boolean; awarded?: boolean; points?: number; skipped?: boolean };
  if (row.skipped || row.awarded === false) {
    return { ok: true, skipped: true, reason: 'already_awarded_or_no_program', points: 0 };
  }

  const points = Number(row.points ?? 0);
  if (points > 0) {
    await emitMerchantBusinessEvent(admin, {
      merchantId: input.merchantId,
      eventType: 'loyalty.points_awarded',
      actorType: 'system',
      customerEmail: buyerEmail,
      reference,
      amount,
      currency: input.currency ?? null,
      source: 'payment.recorded',
      idempotencyKey: `loyalty:award:${reference}`,
      payload: { points, transaction_reference: reference },
    });
  }

  return { ok: true, points };
}

/** Store credit redemption at checkout — ledger-only, Paystack for card remainder. */

import type { SupabaseClient } from 'https://esm.sh/@supabase/supabase-js@2';

export type StoreCreditRow = {
  id: string;
  balance_remaining: number;
  currency: string;
  code: string;
};

export async function resolveStoreCreditForCheckout(
  admin: SupabaseClient,
  creditId: string,
  merchantId: string,
  buyerEmail: string,
): Promise<{ ok: true; credit: StoreCreditRow } | { ok: false; message: string }> {
  const email = buyerEmail.trim().toLowerCase();
  if (!creditId || !email.includes('@')) {
    return { ok: false, message: 'Store credit not available' };
  }

  await admin.rpc('_expire_store_credits').then(() => {}, () => {});

  const { data: row, error } = await admin
    .from('merchant_store_credits')
    .select('id, balance_remaining, currency, code, buyer_email, status, expires_at')
    .eq('id', creditId)
    .eq('merchant_id', merchantId)
    .maybeSingle();

  if (error || !row) {
    return { ok: false, message: 'Store credit not found' };
  }
  if (String(row.buyer_email).toLowerCase() !== email) {
    return { ok: false, message: 'Store credit does not match this email' };
  }
  if (row.status !== 'active' || Number(row.balance_remaining) <= 0) {
    return { ok: false, message: 'Store credit is no longer available' };
  }
  if (row.expires_at && new Date(String(row.expires_at)) < new Date()) {
    return { ok: false, message: 'Store credit has expired' };
  }

  return {
    ok: true,
    credit: {
      id: String(row.id),
      balance_remaining: Number(row.balance_remaining),
      currency: String(row.currency || 'ZAR'),
      code: String(row.code),
    },
  };
}

export function splitStoreCreditAmount(orderAmount: number, creditBalance: number): {
  storeCreditApplied: number;
  cardAmount: number;
} {
  const applied = Math.min(Math.max(creditBalance, 0), Math.max(orderAmount, 0));
  const card = Math.round((orderAmount - applied) * 100) / 100;
  return { storeCreditApplied: applied, cardAmount: card > 0 ? card : 0 };
}

export async function redeemStoreCreditIfNeeded(
  admin: SupabaseClient,
  opts: {
    creditId: string | null;
    merchantId: string;
    buyerEmail: string;
    amount: number;
    reference: string;
    transactionId?: string | null;
  },
): Promise<{ ok: boolean; message?: string }> {
  const { creditId, merchantId, buyerEmail, amount, reference, transactionId } = opts;
  if (!creditId || amount <= 0) return { ok: true };

  const { data, error } = await admin.rpc('store_credit_redeem', {
    p_credit_id: creditId,
    p_merchant_id: merchantId,
    p_buyer_email: buyerEmail,
    p_amount: amount,
    p_reference: reference,
    p_transaction_id: transactionId ?? null,
  });

  if (error) {
    console.error('store_credit_redeem failed', error);
    return { ok: false, message: error.message || 'Could not apply store credit' };
  }
  if (!data?.ok) {
    return { ok: false, message: String(data?.error || 'Could not apply store credit') };
  }
  return { ok: true };
}

import { createClient, type SupabaseClient } from 'https://esm.sh/@supabase/supabase-js@2';
import { checkAiCredits, PREMIUM_AI_ACTIONS } from './aiSubscription.ts';

export async function requireUser(admin: SupabaseClient, req: Request): Promise<string | null> {
  const token = (req.headers.get('Authorization') ?? '').replace(/^Bearer\s+/i, '').trim();
  if (!token) return null;
  const { data, error } = await admin.auth.getUser(token);
  if (error || !data?.user?.email) return null;
  return data.user.email.toLowerCase();
}

export async function requireMerchantById(
  admin: SupabaseClient,
  req: Request,
  merchantId: string,
) {
  const email = await requireUser(admin, req);
  if (!email) return null;

  const { data: merchant } = await admin
    .from('merchants')
    .select('id, business_name, country, category, email, subscription_plan, merchant_plan, subscription_status, ai_credits, ai_credits_used, ai_credits_reset_at')
    .eq('id', merchantId)
    .ilike('email', email)
    .maybeSingle();
  if (merchant?.id === merchantId) return merchant;

  const { data: staffRow } = await admin
    .from('merchant_staff')
    .select('merchant_id')
    .ilike('email', email)
    .eq('status', 'active')
    .eq('merchant_id', merchantId)
    .maybeSingle();
  if (!staffRow) return null;

  const { data: staffMerchant } = await admin
    .from('merchants')
    .select('id, business_name, country, category, email, subscription_plan, merchant_plan, subscription_status, ai_credits, ai_credits_used, ai_credits_reset_at')
    .eq('id', merchantId)
    .maybeSingle();
  return staffMerchant?.id === merchantId ? staffMerchant : null;
}

async function resetCreditsIfDue(admin: SupabaseClient, merchantId: string) {
  const { error } = await admin.rpc('reset_merchant_ai_credits_if_due', { p_merchant_id: merchantId });
  if (error && error.code !== '42883') {
    console.warn('reset_merchant_ai_credits_if_due failed', error.message);
  }
}

export async function consumeAiCredit(
  admin: SupabaseClient,
  merchantId: string,
  action: string,
) {
  if (!PREMIUM_AI_ACTIONS.has(action)) {
    return { ok: true as const, credits_remaining: 999 };
  }

  await resetCreditsIfDue(admin, merchantId);
  const { data: row } = await admin
    .from('merchants')
    .select('subscription_plan, merchant_plan, subscription_status, ai_credits, ai_credits_used')
    .eq('id', merchantId)
    .maybeSingle();
  if (!row) return { ok: false as const, status: 404, body: { error: 'Merchant not found.' } };

  const gate = checkAiCredits(row, action);
  if (!gate.ok) {
    return {
      ok: false as const,
      status: gate.code === 'PREMIUM_REQUIRED' ? 402 : 429,
      body: {
        error: gate.message,
        code: gate.code,
        credits_remaining: gate.credits_remaining,
        credits_limit: gate.credits_limit,
      },
    };
  }

  await admin
    .from('merchants')
    .update({ ai_credits_used: Number(row.ai_credits_used ?? 0) + 1 })
    .eq('id', merchantId);

  return {
    ok: true as const,
    credits_remaining: Math.max(0, gate.credits_remaining - 1),
  };
}

import type { SupabaseClient } from 'https://esm.sh/@supabase/supabase-js@2';

const RESEND_API_KEY = Deno.env.get('RESEND_API_KEY') ?? '';
import { DEFAULT_NOTIFY_FROM } from './platformEmail.ts';

const NOTIFY_FROM = Deno.env.get('NOTIFY_FROM') ?? DEFAULT_NOTIFY_FROM;
const APP_URL = Deno.env.get('APP_URL') ?? 'https://redfacepay.co.za';
const REMINDER_AFTER_HOURS = Number(Deno.env.get('ABANDONED_CART_REMINDER_HOURS') ?? '24');

async function sendEmail(to: string, subject: string, html: string): Promise<boolean> {
  if (!RESEND_API_KEY || !to) return false;
  const res = await fetch('https://api.resend.com/emails', {
    method: 'POST',
    headers: {
      Authorization: `Bearer ${RESEND_API_KEY}`,
      'Content-Type': 'application/json',
    },
    body: JSON.stringify({ from: NOTIFY_FROM, to: [to], subject, html }),
  });
  return res.ok;
}

export async function markAbandonedCartRecovered(
  admin: SupabaseClient,
  merchantId: string,
  buyerEmail: string,
) {
  const email = buyerEmail.toLowerCase().trim();
  if (!email || !merchantId) return;
  await admin
    .from('merchant_abandoned_carts')
    .update({
      status: 'recovered',
      recovered_at: new Date().toISOString(),
    })
    .eq('merchant_id', merchantId)
    .eq('buyer_email', email)
    .eq('status', 'active');
}

export async function processAbandonedCartReminders(admin: SupabaseClient): Promise<{
  sent: number;
  expired: number;
}> {
  const cutoff = new Date(Date.now() - REMINDER_AFTER_HOURS * 3600000).toISOString();
  const expireBefore = new Date(Date.now() - 30 * 86400000).toISOString();

  const { data: expiredRows } = await admin
    .from('merchant_abandoned_carts')
    .update({ status: 'expired' })
    .eq('status', 'active')
    .lt('updated_at', expireBefore)
    .select('id');

  const expired = expiredRows?.length ?? 0;

  const { data: rows } = await admin
    .from('merchant_abandoned_carts')
    .select('id, buyer_email, subtotal, currency, recovery_token, merchant_id, item_count')
    .eq('status', 'active')
    .is('reminder_sent_at', null)
    .lt('updated_at', cutoff)
    .limit(50);

  let sent = 0;
  for (const row of rows || []) {
    const { data: merchant } = await admin
      .from('merchants')
      .select('business_name')
      .eq('id', row.merchant_id)
      .maybeSingle();
    const name = merchant?.business_name || 'your seller';
    const recoveryUrl = `${APP_URL}/?view=cart&recover=${row.recovery_token}`;
    const amount = Number(row.subtotal).toFixed(2);
    const ccy = row.currency || 'ZAR';

    const ok = await sendEmail(
      row.buyer_email,
      `Complete your order at ${name}`,
      `<p>You left ${row.item_count} item(s) in your cart at <strong>${name}</strong> (${ccy} ${amount}).</p>
       <p><a href="${recoveryUrl}">Return to checkout</a> to complete your purchase.</p>
       <p style="color:#888;font-size:12px">If you already paid, you can ignore this email.</p>`,
    );

    if (ok) {
      await admin
        .from('merchant_abandoned_carts')
        .update({ reminder_sent_at: new Date().toISOString() })
        .eq('id', row.id);
      sent++;
    }
  }

  return { sent, expired };
}

/**
 * SoftPOS country / entitlement gate.
 *
 * A Swiss Stripe platform account does NOT imply SoftPOS in South Africa.
 * Availability follows Stripe Terminal Tap to Pay country lists + merchant
 * operating country (Terminal Location), plus explicit entitlement.
 *
 * Sources (GA, not preview): Stripe Tap to Pay docs — iOS + Android.
 * Update when Stripe expands markets; do not invent ZA support.
 */

/** Countries where Stripe Tap to Pay is generally available (union iOS + Android GA). */
export const STRIPE_TERMINAL_TTP_COUNTRIES = new Set([
  'AT',
  'AU',
  'BE',
  'CA',
  'CH',
  'CZ',
  'DE',
  'DK',
  'ES',
  'FI',
  'FR',
  'GB',
  'IE',
  'IT',
  'MY',
  'NL',
  'NZ',
  'PL',
  'PT',
  'SE',
  'SG',
  'US',
]);

export function normalizeSoftposCountry(country?: string | null): string {
  return String(country ?? '').trim().toUpperCase() || 'ZA';
}

/** Stripe Terminal Tap to Pay may be offered only in these operating countries. */
export function isStripeTerminalTtpCountry(country?: string | null): boolean {
  return STRIPE_TERMINAL_TTP_COUNTRIES.has(normalizeSoftposCountry(country));
}

/**
 * SoftPOS offered to the merchant UI / routing.
 * ZA SoftPOS requires a local partner entitlement — never Stripe TTP by default.
 */
export function resolveSoftposOffer(ctx: {
  country?: string | null;
  stripeTerminalEntitled?: boolean;
  saPartner?: 'istore_tap' | 'yoco_tap' | null;
  allowSimulator?: boolean;
}): {
  offered: boolean;
  providerId: 'stripe_terminal' | 'istore_tap' | 'yoco_tap' | 'simulator' | null;
  reason: string;
} {
  const country = normalizeSoftposCountry(ctx.country);

  if (ctx.allowSimulator && Deno.env.get('SOFTPOS_SIMULATOR') === '1') {
    return { offered: true, providerId: 'simulator', reason: 'SOFTPOS_SIMULATOR=1' };
  }

  if (ctx.saPartner === 'istore_tap' && country === 'ZA') {
    return { offered: true, providerId: 'istore_tap', reason: 'ZA SoftPOS via iStore entitlement' };
  }
  if (ctx.saPartner === 'yoco_tap' && country === 'ZA') {
    return { offered: true, providerId: 'yoco_tap', reason: 'ZA SoftPOS via Yoco entitlement' };
  }

  // Stripe TTP: requires Terminal-supported operating country AND entitlement.
  // Env SOFTPOS_STRIPE_ENABLED=1 unlocks after Stripe confirms the business case.
  const stripeEnabled = Deno.env.get('SOFTPOS_STRIPE_ENABLED') === '1';
  if (
    stripeEnabled &&
    ctx.stripeTerminalEntitled &&
    isStripeTerminalTtpCountry(country)
  ) {
    return {
      offered: true,
      providerId: 'stripe_terminal',
      reason: `Stripe Terminal Tap to Pay for ${country}`,
    };
  }

  if (country === 'ZA') {
    return {
      offered: false,
      providerId: null,
      reason:
        'SoftPOS not live in ZA via Stripe Terminal; awaiting SA SoftPOS partner or Stripe confirmation',
    };
  }

  if (isStripeTerminalTtpCountry(country) && !stripeEnabled) {
    return {
      offered: false,
      providerId: null,
      reason: 'Stripe Terminal country, but SoftPOS gated until SOFTPOS_STRIPE_ENABLED=1 and entitlement',
    };
  }

  return {
    offered: false,
    providerId: null,
    reason: `SoftPOS not available for operating country ${country}`,
  };
}

/**
 * Ledger Engine — the mandatory write path for payment truth.
 *
 * Platform Invariants (docs/codex/platform/platform-invariants.md):
 * - IX: The Ledger is the source of truth; providers are external evidence.
 * - III/IV: Every write is idempotent; entries are immutable after commit.
 */

import type { SupabaseClient } from 'https://esm.sh/@supabase/supabase-js@2';
import { appendPlatformPaymentEvent } from './platformPaymentSpine.ts';
import { consumePaymentRecorded } from './consumePaymentRecorded.ts';
import {
  createBusinessFactEnvelope,
  envelopeIntoPayload,
} from './businessFactEnvelope.ts';

export type LedgerRecordResult = {
  ok: boolean;
  created: boolean;
  error?: string;
  factId?: string | null;
};

export async function recordPaymentLedgerEntry(
  admin: SupabaseClient,
  opts: {
    reference: string;
    processingRail?: string | null;
    app?: string | null;
  },
): Promise<LedgerRecordResult> {
  const reference = String(opts.reference ?? '').trim();
  if (!reference) return { ok: false, created: false, error: 'reference_required' };

  const { data, error } = await admin.rpc('record_payment_ledger_entry', {
    p_reference: reference,
    p_processing_rail: opts.processingRail ?? null,
  });
  if (error) {
    console.error('record_payment_ledger_entry', reference, error.message);
    return { ok: false, created: false, error: error.message };
  }

  const row = (data ?? {}) as Record<string, unknown>;
  if (row.ok !== true) {
    return { ok: false, created: false, error: String(row.error ?? 'ledger_write_failed') };
  }

  const created = row.created === true;
  let factId: string | null = null;
  if (created) {
    const merchantId = typeof row.merchant_id === 'string' ? row.merchant_id : null;
    const envelope = createBusinessFactEnvelope({
      type: 'payment.recorded',
      producer: 'commerce-kernel.ledger',
      merchantId,
      reference,
      payload: {
        txn_key: row.txn_key ?? null,
        business_intent: row.business_intent ?? null,
        processing_rail: row.processing_rail ?? opts.processingRail ?? null,
      },
    });

    factId = await appendPlatformPaymentEvent(admin, {
      eventType: envelope.type,
      reference,
      idempotencyKey: `ledger:${reference}`,
      app: opts.app ?? null,
      merchantId,
      amount: typeof row.amount === 'number' ? row.amount : Number(row.amount ?? 0) || null,
      currency: typeof row.currency === 'string' ? row.currency : null,
      payload: envelopeIntoPayload(envelope),
      correlationId: envelope.correlation_id,
      causationId: envelope.causation_id,
      eventVersion: envelope.version,
      producer: envelope.producer,
    });

    await consumePaymentRecorded(admin, {
      reference,
      merchantId,
      amount: typeof row.amount === 'number' ? row.amount : Number(row.amount ?? 0) || null,
      currency: typeof row.currency === 'string' ? row.currency : null,
      businessIntent: typeof row.business_intent === 'string' ? row.business_intent : null,
      processingRail: typeof row.processing_rail === 'string' ? row.processing_rail : null,
      txnKey: typeof row.txn_key === 'string' ? row.txn_key : null,
      correlationId: envelope.correlation_id,
      causationId: factId ?? envelope.id,
    });
  }
  return { ok: true, created, factId };
}

// AI subscription + monthly credit limits for merchant growth features.

export type SubscriptionPlan = 'free' | 'premium' | 'business';

export const AI_MONTHLY_LIMITS: Record<SubscriptionPlan, number> = {
  free: 10,
  premium: 500,
  business: 5000,
};

export const PREMIUM_AI_ACTIONS = new Set([
  'ask',
  'insights',
  'marketing',
  'sales_coach',
  'find_leads',
  'suggest_nfc_tags',
  'scan_receipt',
  'catalog',
]);

export function effectiveSubscriptionPlan(row: {
  subscription_plan?: string | null;
  merchant_plan?: string | null;
  subscription_status?: string | null;
}): SubscriptionPlan {
  const plan = String(row.subscription_plan ?? '').toLowerCase();
  if (plan === 'premium' || plan === 'business') return plan;
  if (row.merchant_plan === 'premium' && row.subscription_status === 'active') return 'premium';
  return 'free';
}

export function monthlyAiLimit(plan: SubscriptionPlan): number {
  return AI_MONTHLY_LIMITS[plan];
}

export type AiCreditResult =
  | { ok: true; plan: SubscriptionPlan; credits_remaining: number; credits_limit: number }
  | { ok: false; code: 'PREMIUM_REQUIRED' | 'CREDITS_EXHAUSTED'; message: string; credits_remaining: number; credits_limit: number; plan: SubscriptionPlan };

export function checkAiCredits(row: {
  subscription_plan?: string | null;
  merchant_plan?: string | null;
  subscription_status?: string | null;
  ai_credits?: number | null;
  ai_credits_used?: number | null;
}, action: string): AiCreditResult {
  if (!PREMIUM_AI_ACTIONS.has(action)) {
    return { ok: true, plan: 'free', credits_remaining: 999, credits_limit: 999 };
  }

  const plan = effectiveSubscriptionPlan(row);
  const limit = Number(row.ai_credits ?? monthlyAiLimit(plan)) || monthlyAiLimit(plan);
  const used = Number(row.ai_credits_used ?? 0);
  const remaining = Math.max(0, limit - used);

  if (remaining <= 0) {
    if (plan === 'free') {
      return {
        ok: false,
        code: 'PREMIUM_REQUIRED',
        message: 'You have used your 10 free AI requests this month. Upgrade to Premium for 500 AI requests and the full growth suite.',
        credits_remaining: 0,
        credits_limit: limit,
        plan,
      };
    }
    return {
      ok: false,
      code: 'CREDITS_EXHAUSTED',
      message: `You have used all ${limit} AI credits this month. Credits reset at the start of next month.`,
      credits_remaining: 0,
      credits_limit: limit,
      plan,
    };
  }

  return { ok: true, plan, credits_remaining: remaining, credits_limit: limit };
}

export function premiumActivationPatch(now = new Date()) {
  const end = new Date(now);
  end.setMonth(end.getMonth() + 1);
  return {
    merchant_plan: 'premium',
    subscription_plan: 'premium',
    subscription_status: 'active',
    subscription_start: now.toISOString(),
    subscription_end: end.toISOString(),
    ai_credits: AI_MONTHLY_LIMITS.premium,
    ai_credits_used: 0,
    ai_credits_reset_at: new Date(Date.UTC(now.getUTCFullYear(), now.getUTCMonth(), 1)).toISOString(),
  };
}

export function freePlanPatch(now = new Date()) {
  return {
    merchant_plan: 'small',
    subscription_plan: 'free',
    subscription_status: 'cancelled',
    ai_credits: AI_MONTHLY_LIMITS.free,
    ai_credits_used: 0,
    ai_credits_reset_at: new Date(Date.UTC(now.getUTCFullYear(), now.getUTCMonth(), 1)).toISOString(),
  };
}

/** Resolve POS cart lines from product / variant IDs. */

import type { SupabaseClient } from 'https://esm.sh/@supabase/supabase-js@2';

export type CartLine = {
  product_id: string;
  name: string;
  price: number;
  quantity: number;
  variant_id?: string;
  variant_label?: string;
  category_id?: string;
  category?: string;
};

export async function resolveCartItems(
  admin: SupabaseClient,
  merchantId: string,
  cartItems: unknown,
): Promise<{ items: CartLine[]; total: number } | { error: string }> {
  const raw = Array.isArray(cartItems) ? cartItems : [];
  if (!raw.length) return { error: 'cart_items is empty' };

  const lines: CartLine[] = [];
  let total = 0;
  for (const row of raw) {
    const rec = row as Record<string, unknown>;
    const productId = String(rec.product_id ?? '').trim();
    const variantId = String(rec.variant_id ?? rec.variantId ?? '').trim() || null;
    const qty = Math.max(1, Math.min(99, Number(rec.quantity ?? rec.qty) || 1));
    if (!productId) return { error: 'cart item missing product_id' };

    const { data: p } = await admin
      .from('products')
      .select('id, name, price, merchant_id, billing_type, track_inventory, stock_quantity, category_id')
      .eq('id', productId)
      .eq('merchant_id', merchantId)
      .maybeSingle();
    if (!p) return { error: 'A product in your cart is no longer available' };
    if (p.billing_type === 'subscription') {
      return { error: 'Subscription products must be purchased separately' };
    }

    let unitPrice = Number(p.price);
    let variantLabel: string | null = null;
    if (variantId) {
      const { data: variant } = await admin
        .from('product_variants')
        .select('id, label, price, stock_quantity, active')
        .eq('id', variantId)
        .eq('product_id', productId)
        .maybeSingle();
      if (!variant || !variant.active) return { error: 'A selected size/variant is no longer available' };
      unitPrice = Number(variant.price ?? p.price);
      variantLabel = variant.label;
      if (variant.stock_quantity != null && Number(variant.stock_quantity) < qty) {
        return { error: `${p.name} (${variant.label}) is out of stock` };
      }
    } else if (p.track_inventory && Number(p.stock_quantity || 0) < qty) {
      return { error: `${p.name} is out of stock` };
    }

    let categoryId: string | undefined;
    let categoryName: string | undefined;
    if (p.category_id) {
      categoryId = String(p.category_id);
      const { data: cat } = await admin
        .from('product_categories')
        .select('id, name')
        .eq('id', p.category_id)
        .maybeSingle();
      if (cat?.name) categoryName = String(cat.name);
    }

    lines.push({
      product_id: p.id,
      name: p.name,
      price: unitPrice,
      quantity: qty,
      ...(variantId ? { variant_id: variantId, variant_label: variantLabel ?? undefined } : {}),
      ...(categoryId ? { category_id: categoryId } : {}),
      ...(categoryName ? { category: categoryName } : {}),
    });
    total += unitPrice * qty;
  }
  if (!(total > 0)) return { error: 'cart total must be greater than zero' };
  return { items: lines, total };
}

export function cartLabel(lines: CartLine[]): string {
  if (lines.length === 1) {
    const l = lines[0];
    return l.quantity > 1 ? `${l.name} × ${l.quantity}` : l.name;
  }
  const units = lines.reduce((n, l) => n + l.quantity, 0);
  return `${lines.length} items (${units} units)`;
}

import type {
  InitializeCheckoutInput,
  InitializeCheckoutResult,
  PaymentProvider,
  VerifyTransactionResult,
} from './types.ts';

const STRIPE_API = 'https://api.stripe.com/v1';

function formBody(params: Record<string, string>): string {
  return new URLSearchParams(params).toString();
}

export function createStripeProvider(secretKey: string): PaymentProvider {
  return {
    name: 'stripe',
    async initializeCheckout(input: InitializeCheckoutInput): Promise<InitializeCheckoutResult> {
      if (!secretKey?.startsWith('sk_')) {
        return { ok: false, provider: 'stripe', message: 'STRIPE_SECRET_KEY is not configured' };
      }
      try {
        const res = await fetch(`${STRIPE_API}/checkout/sessions`, {
          method: 'POST',
          headers: {
            Authorization: `Bearer ${secretKey}`,
            'Content-Type': 'application/x-www-form-urlencoded',
          },
          body: formBody({
            mode: 'payment',
            success_url: `${input.callbackUrl}?stripe=success&reference=${encodeURIComponent(input.reference)}`,
            cancel_url: `${input.callbackUrl}?stripe=cancel&reference=${encodeURIComponent(input.reference)}`,
            customer_email: input.email,
            client_reference_id: input.reference,
            'line_items[0][price_data][currency]': input.currency.toLowerCase(),
            'line_items[0][price_data][unit_amount]': String(input.amountSubunits),
            'line_items[0][price_data][product_data][name]': String(input.metadata?.label ?? 'RedFace Pay'),
            'line_items[0][quantity]': '1',
            'metadata[merchant_id]': String(input.metadata?.merchant_id ?? ''),
            'metadata[reference]': input.reference,
          }),
        });
        const data = await res.json().catch(() => ({})) as {
          error?: { message?: string };
          url?: string;
          id?: string;
        };
        if (!res.ok) {
          return { ok: false, provider: 'stripe', message: data.error?.message || 'Stripe checkout failed' };
        }
        return {
          ok: true,
          provider: 'stripe',
          reference: input.reference,
          authorization_url: data.url,
          access_code: data.id,
        };
      } catch (err) {
        return { ok: false, provider: 'stripe', message: err instanceof Error ? err.message : 'Stripe error' };
      }
    },

    async verifyTransaction(reference: string): Promise<VerifyTransactionResult> {
      if (!secretKey?.startsWith('sk_')) {
        return { ok: false, provider: 'stripe', message: 'STRIPE_SECRET_KEY is not configured' };
      }
      try {
        const res = await fetch(
          `${STRIPE_API}/checkout/sessions?limit=1&client_reference_id=${encodeURIComponent(reference)}`,
          { headers: { Authorization: `Bearer ${secretKey}` } },
        );
        const data = await res.json().catch(() => ({})) as {
          error?: { message?: string };
          data?: Array<{ payment_status?: string; amount_total?: number; currency?: string }>;
        };
        if (!res.ok) {
          return { ok: false, provider: 'stripe', message: data.error?.message || 'Stripe verify failed' };
        }
        const session = data.data?.[0];
        return {
          ok: true,
          provider: 'stripe',
          status: session?.payment_status,
          amountSubunits: session?.amount_total,
          currency: session?.currency?.toUpperCase(),
        };
      } catch (err) {
        return { ok: false, provider: 'stripe', message: err instanceof Error ? err.message : 'Stripe error' };
      }
    },
  };
}

/**
 * Review + thank-you lifecycle from payment.recorded.
 * Immediate thank-you email; review invite after 24h via customer_review_requests cron.
 */

import type { SupabaseClient } from 'https://esm.sh/@supabase/supabase-js@2';
import { emitMerchantBusinessEvent } from './businessEvents.ts';

const NON_REVIEW_PURCHASE_TYPES = new Set([
  'domain',
  'domain_renewal',
  'plan_subscription',
  'product_subscription',
  'developer_api_subscription',
  'sponsored_listing',
  'agency',
  'studio_subscription',
  'bank_transfer',
]);

export async function consumeReviewLifecycleFromPaymentRecorded(
  admin: SupabaseClient,
  input: {
    reference: string;
    merchantId: string;
    buyerEmail?: string | null;
    amount?: number | null;
    currency?: string | null;
    purchaseType?: string | null;
    correlationId?: string | null;
    causationId?: string | null;
  },
): Promise<{ ok: boolean; skipped?: boolean; reason?: string }> {
  const reference = String(input.reference ?? '').trim();
  const buyerEmail = String(input.buyerEmail ?? '').trim().toLowerCase();
  if (!reference || !buyerEmail) {
    return { ok: true, skipped: true, reason: 'no_buyer_email' };
  }

  const purchaseType = String(input.purchaseType ?? '').toLowerCase();
  if (purchaseType && NON_REVIEW_PURCHASE_TYPES.has(purchaseType)) {
    return { ok: true, skipped: true, reason: 'non_review_purchase' };
  }

  const { data: merchant } = await admin
    .from('merchants')
    .select('business_name')
    .eq('id', input.merchantId)
    .maybeSingle();
  const merchantName = String(merchant?.business_name || 'your merchant').trim() || 'your merchant';

  const thankYouBody =
    `Hi,\n\n` +
    `Thank you for shopping with ${merchantName}.\n\n` +
    `Your payment has been received successfully. We appreciate your support.\n\n` +
    `If you need help, contact ${merchantName}.\n\n` +
    `Thank you for using RedFace Pay.`;

  await admin.rpc('enqueue_platform_notification', {
    p_channel: 'email',
    p_recipient: buyerEmail,
    p_event_type: 'purchase_thank_you',
    p_body: thankYouBody,
    p_payload: {
      reference,
      merchant_id: input.merchantId,
      amount: input.amount ?? null,
      currency: input.currency ?? null,
    },
    p_subject: `Thank you for your purchase at ${merchantName}`,
    p_merchant_id: input.merchantId,
    p_reference: reference,
  });

  const { data: allowsReview } = await admin.rpc('customer_allows_review_requests', {
    p_merchant_id: input.merchantId,
    p_email: buyerEmail,
  });
  if (allowsReview === false) {
    return { ok: true, skipped: true, reason: 'review_requests_disabled' };
  }

  const { data: created, error } = await admin.rpc('create_review_request_from_payment', {
    p_reference: reference,
  });
  if (error) {
    console.error('create_review_request_from_payment', reference, error.message);
    return { ok: false, reason: error.message };
  }

  const row = (created ?? {}) as {
    ok?: boolean;
    skipped?: boolean;
    reason?: string;
    id?: string;
    public_token?: string;
  };

  if (row.ok && !row.skipped && row.id) {
    await emitMerchantBusinessEvent(admin, {
      merchantId: input.merchantId,
      eventType: 'review_request_queued',
      actorType: 'system',
      customerEmail: buyerEmail,
      reference,
      amount: input.amount ?? null,
      currency: input.currency ?? null,
      source: 'payment.recorded',
      idempotencyKey: `review_request_queued:${reference}`,
      payload: {
        review_request_id: row.id,
        public_token: row.public_token ?? null,
        send_after_hours: 24,
        correlation_id: input.correlationId ?? null,
        causation_id: input.causationId ?? null,
      },
    });
  }

  return { ok: true, skipped: Boolean(row.skipped), reason: row.reason };
}

import type { SupabaseClient } from 'https://esm.sh/@supabase/supabase-js@2';

export type DvaCountry = { code: 'NG' | 'GH'; currency: string };

export function dvaEligibleCountry(country: string | null | undefined): DvaCountry | null {
  const c = String(country ?? '').trim().toLowerCase();
  if (c === 'nigeria' || c === 'ng') return { code: 'NG', currency: 'NGN' };
  if (c === 'ghana' || c === 'gh') return { code: 'GH', currency: 'GHS' };
  return null;
}

export function splitMerchantContactName(businessName: string): { firstName: string; lastName: string } {
  const parts = String(businessName ?? '').trim().split(/\s+/).filter(Boolean);
  if (parts.length === 0) return { firstName: 'Merchant', lastName: 'Account' };
  if (parts.length === 1) return { firstName: parts[0], lastName: 'Business' };
  return { firstName: parts[0], lastName: parts.slice(1).join(' ') };
}

export type PaystackDvaPayload = Record<string, unknown>;

export async function upsertMerchantDedicatedAccount(
  admin: SupabaseClient,
  merchantId: string,
  dvaData: PaystackDvaPayload,
  patch: { status?: string; error_message?: string | null } = {},
): Promise<void> {
  const bank = (dvaData.bank ?? {}) as Record<string, unknown>;
  const customer = (dvaData.customer ?? {}) as Record<string, unknown>;
  const countryCode = String(dvaData.currency ?? 'NGN').toUpperCase() === 'GHS' ? 'GH' : 'NG';
  const active = dvaData.active === true || dvaData.active === 1 || dvaData.assigned === true;

  await admin.from('merchant_dedicated_accounts').upsert({
    merchant_id: merchantId,
    status: patch.status ?? (active ? 'active' : 'pending'),
    country_code: countryCode,
    currency: String(dvaData.currency ?? (countryCode === 'GH' ? 'GHS' : 'NGN')).toUpperCase(),
    paystack_customer_code: customer.customer_code ? String(customer.customer_code) : null,
    paystack_dva_id: dvaData.id != null ? String(dvaData.id) : null,
    account_number: dvaData.account_number ? String(dvaData.account_number) : null,
    account_name: dvaData.account_name ? String(dvaData.account_name) : null,
    bank_name: bank.name ? String(bank.name) : null,
    bank_slug: bank.slug ? String(bank.slug) : null,
    is_active: active,
    error_message: patch.error_message ?? null,
    meta: dvaData,
    updated_at: new Date().toISOString(),
  }, { onConflict: 'merchant_id' });
}

export async function resolveMerchantFromDedicatedAccountNumber(
  admin: SupabaseClient,
  accountNumber: string,
): Promise<string | null> {
  const num = String(accountNumber ?? '').trim();
  if (!num) return null;
  const { data } = await admin
    .from('merchant_dedicated_accounts')
    .select('merchant_id')
    .eq('account_number', num)
    .eq('is_active', true)
    .maybeSingle();
  return (data?.merchant_id as string) ?? null;
}

export async function resolveMerchantIdForDvaWebhook(
  admin: SupabaseClient,
  data: Record<string, unknown>,
): Promise<string | null> {
  const dva = (data.dedicated_account ?? data) as PaystackDvaPayload;
  const accountNumber = String(dva.account_number ?? '').trim();
  if (accountNumber) {
    const byNumber = await resolveMerchantFromDedicatedAccountNumber(admin, accountNumber);
    if (byNumber) return byNumber;
  }

  const customer = (data.customer ?? dva.customer ?? {}) as Record<string, unknown>;
  const email = String(customer.email ?? '').trim().toLowerCase();
  if (email) {
    const { data: merchant } = await admin
      .from('merchants')
      .select('id')
      .ilike('email', email)
      .eq('status', 'approved')
      .maybeSingle();
    if (merchant?.id) return String(merchant.id);
  }

  const customerCode = String(customer.customer_code ?? '').trim();
  if (customerCode) {
    const { data: row } = await admin
      .from('merchant_dedicated_accounts')
      .select('merchant_id')
      .eq('paystack_customer_code', customerCode)
      .maybeSingle();
    if (row?.merchant_id) return String(row.merchant_id);
  }

  return null;
}

import type {
  InitializeCheckoutInput,
  InitializeCheckoutResult,
  PaymentProvider,
  VerifyTransactionResult,
} from './types.ts';

const PAYSTACK_BASE = 'https://api.paystack.co';

async function paystackPost(secret: string, path: string, body: unknown) {
  const res = await fetch(`${PAYSTACK_BASE}${path}`, {
    method: 'POST',
    headers: {
      Authorization: `Bearer ${secret}`,
      'Content-Type': 'application/json',
    },
    body: JSON.stringify(body),
  });
  const data = await res.json().catch(() => ({}));
  if (!res.ok) {
    return { status: false, message: (data as { message?: string }).message || res.statusText, data };
  }
  return { status: true, data: (data as { data?: Record<string, unknown> }).data, message: (data as { message?: string }).message };
}

async function paystackGet(secret: string, path: string) {
  const res = await fetch(`${PAYSTACK_BASE}${path}`, {
    headers: { Authorization: `Bearer ${secret}` },
  });
  const data = await res.json().catch(() => ({}));
  if (!res.ok) {
    return { status: false, message: (data as { message?: string }).message || res.statusText, data };
  }
  return { status: true, data: (data as { data?: Record<string, unknown> }).data };
}

export function createPaystackProvider(secretKey: string): PaymentProvider {
  return {
    name: 'paystack',
    async initializeCheckout(input: InitializeCheckoutInput): Promise<InitializeCheckoutResult> {
      const payload: Record<string, unknown> = {
        email: input.email,
        amount: input.amountSubunits,
        currency: input.currency,
        reference: input.reference,
        callback_url: input.callbackUrl,
        metadata: input.metadata ?? {},
      };
      if (input.subaccount) payload.subaccount = input.subaccount;
      if (input.channels?.length) payload.channels = input.channels;

      const ps = await paystackPost(secretKey, '/transaction/initialize', payload);
      if (!ps.status) {
        return { ok: false, provider: 'paystack', message: ps.message || 'Paystack initialize failed' };
      }
      const row = ps.data ?? {};
      return {
        ok: true,
        provider: 'paystack',
        reference: String(row.reference ?? input.reference),
        access_code: row.access_code ? String(row.access_code) : undefined,
        authorization_url: row.authorization_url ? String(row.authorization_url) : undefined,
      };
    },

    async verifyTransaction(reference: string): Promise<VerifyTransactionResult> {
      const ps = await paystackGet(secretKey, `/transaction/verify/${encodeURIComponent(reference)}`);
      if (!ps.status) {
        return { ok: false, provider: 'paystack', message: ps.message || 'Verify failed' };
      }
      const row = (ps.data ?? {}) as Record<string, unknown>;
      const metadata =
        row.metadata && typeof row.metadata === 'object' && !Array.isArray(row.metadata)
          ? (row.metadata as Record<string, unknown>)
          : undefined;
      return {
        ok: true,
        provider: 'paystack',
        status: String(row.status ?? ''),
        amountSubunits: Number(row.amount) || undefined,
        currency: row.currency ? String(row.currency) : undefined,
        metadata,
        message: typeof ps.message === 'string' ? ps.message : undefined,
      };
    },
  };
}

/** Full Paystack initialize payload (split codes, subaccount routing, etc.). */
export async function initializePaystackCheckoutFull(
  secretKey: string,
  payload: Record<string, unknown>,
): Promise<InitializeCheckoutResult> {
  const ps = await paystackPost(secretKey, '/transaction/initialize', payload);
  if (!ps.status) {
    return { ok: false, provider: 'paystack', message: ps.message || 'Paystack initialize failed' };
  }
  const row = ps.data ?? {};
  return {
    ok: true,
    provider: 'paystack',
    reference: String(row.reference ?? payload.reference ?? ''),
    access_code: row.access_code ? String(row.access_code) : undefined,
    authorization_url: row.authorization_url ? String(row.authorization_url) : undefined,
  };
}

import type { SupabaseClient } from 'https://esm.sh/@supabase/supabase-js@2';

const TOKEN_TTL_HOURS = 24;
const RESEND_COOLDOWN_MS = 5 * 60 * 1000;
const MAX_RESENDS_PER_DAY = 5;

async function hashToken(token: string): Promise<string> {
  const data = new TextEncoder().encode(token);
  const hash = await crypto.subtle.digest('SHA-256', data);
  return Array.from(new Uint8Array(hash))
    .map((b) => b.toString(16).padStart(2, '0'))
    .join('');
}

function appOrigin(): string {
  return (Deno.env.get('APP_URL') ?? 'https://www.redfacepay.co.za').replace(/\/$/, '');
}

async function nudgeNotificationService(): Promise<void> {
  const url = `${Deno.env.get('SUPABASE_URL') ?? ''}/functions/v1/notification-service`;
  const secret = Deno.env.get('CRON_SECRET') ?? '';
  if (!url || !secret) return;
  try {
    await fetch(url, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'x-cron-secret': secret,
      },
      body: JSON.stringify({ action: 'process_outbox', limit: 10 }),
    });
  } catch {
    /* cron will retry */
  }
}

export async function sendSignupVerificationEmail(
  admin: SupabaseClient,
  rawEmail: string,
): Promise<{ ok: boolean; message: string; alreadyVerified?: boolean }> {
  const email = rawEmail.trim().toLowerCase();
  if (!email || !email.includes('@')) {
    return { ok: false, message: 'Enter a valid email address.' };
  }

  const { data: verified } = await admin.rpc('is_signup_email_verified', { p_email: email });
  if (verified) {
    return { ok: true, message: 'Email already verified. You can sign in.', alreadyVerified: true };
  }

  const { data: existing } = await admin
    .from('user_signup_email_verifications')
    .select('email, resent_count, last_sent_at, verified_at')
    .eq('email', email)
    .maybeSingle();

  if (existing?.verified_at) {
    return { ok: true, message: 'Email already verified. You can sign in.', alreadyVerified: true };
  }

  const now = Date.now();
  if (existing?.last_sent_at) {
    const lastSent = new Date(String(existing.last_sent_at)).getTime();
    if (now - lastSent < RESEND_COOLDOWN_MS) {
      return {
        ok: true,
        message: 'Verification email already sent. Check your inbox (and spam), or wait a few minutes to resend.',
      };
    }
    if (Number(existing.resent_count ?? 0) >= MAX_RESENDS_PER_DAY) {
      return { ok: false, message: 'Too many verification emails today. Try again tomorrow or contact support.' };
    }
  }

  const token = crypto.randomUUID().replace(/-/g, '') + crypto.randomUUID().replace(/-/g, '');
  const tokenHash = await hashToken(token);
  const expiresAt = new Date(now + TOKEN_TTL_HOURS * 60 * 60 * 1000).toISOString();
  const verifyUrl = `${appOrigin()}/verify-email?token=${encodeURIComponent(token)}`;
  const loginUrl = `${appOrigin()}/login`;

  const { error: upsertErr } = await admin.from('user_signup_email_verifications').upsert({
    email,
    token_hash: tokenHash,
    expires_at: expiresAt,
    verified_at: null,
    resent_count: Number(existing?.resent_count ?? 0) + (existing ? 1 : 0),
    last_sent_at: new Date().toISOString(),
  });
  if (upsertErr) {
    return { ok: false, message: 'Could not start verification. Try again.' };
  }

  const body = [
    'Welcome to RedFace Pay!',
    '',
    'Verify your email to activate your account:',
    verifyUrl,
    '',
    `This link expires in ${TOKEN_TTL_HOURS} hours.`,
    '',
    `After verifying, sign in here: ${loginUrl}`,
    '',
    'If you did not create a RedFace account, you can ignore this email.',
  ].join('\n');

  await admin.rpc('enqueue_platform_notification', {
    p_channel: 'email',
    p_recipient: email,
    p_event_type: 'signup_verification',
    p_body: body,
    p_payload: { verify_url: verifyUrl, login_url: loginUrl },
    p_subject: 'Verify your RedFace Pay email',
    p_reference: `signup_verify:${email}`,
  }).then(() => {}, () => {});

  void nudgeNotificationService();

  return {
    ok: true,
    message: 'Verification email sent. Check your inbox, then sign in after you verify.',
  };
}
